import React, { useState } from 'react';

export default function Quiz({ questions }) {
  const [i, setI] = useState(0);
  const [answers, setAnswers] = useState({});

  const done = i >= questions.length;

  const pick = (choice) => {
    if (answers[i] != null) return;
    setAnswers((a) => ({ ...a, [i]: choice }));
  };

  const restart = () => {
    setI(0);
    setAnswers({});
  };

  if (done) {
    const score = questions.reduce((s, q, idx) => s + (answers[idx] === q.correct ? 1 : 0), 0);
    return (
      <div style={{ maxWidth: 460 }}>
        <h2>Score: {score} / {questions.length}</h2>
        <ul style={{ paddingLeft: 18 }}>
          {questions.map((q, idx) => (
            <li key={idx} style={{ marginBottom: 6, color: answers[idx] === q.correct ? '#16a34a' : '#dc2626' }}>
              {q.q} — {q.options[q.correct]}
            </li>
          ))}
        </ul>
        <button onClick={restart} style={{ padding: '8px 16px', cursor: 'pointer' }}>Restart</button>
      </div>
    );
  }

  const q = questions[i];
  const chosen = answers[i];

  return (
    <div style={{ maxWidth: 460 }}>
      <p style={{ color: '#888' }}>Question {i + 1} of {questions.length}</p>
      <h3>{q.q}</h3>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {q.options.map((opt, idx) => {
          let bg = '#fff';
          if (chosen != null) {
            if (idx === q.correct) bg = '#dcfce7';
            else if (idx === chosen) bg = '#fee2e2';
          }
          return (
            <button
              key={idx}
              onClick={() => pick(idx)}
              style={{ textAlign: 'left', padding: '10px 14px', borderRadius: 8, border: '1px solid #d1d5db', cursor: chosen != null ? 'default' : 'pointer', background: bg }}
            >
              {opt}
            </button>
          );
        })}
      </div>
      <button
        onClick={() => setI(i + 1)}
        disabled={chosen == null}
        style={{ marginTop: 16, padding: '8px 16px', cursor: chosen == null ? 'default' : 'pointer', opacity: chosen == null ? 0.5 : 1 }}
      >
        {i === questions.length - 1 ? 'Finish' : 'Next'}
      </button>
    </div>
  );
}

