import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Question { q: string; options: string[]; correct: number; }

@Component({
  selector: 'app-quiz',
  template: `
    <div style="max-width: 460px;">
      <ng-container *ngIf="!done; else result">
        <p style="color: #888;">Question {{ i + 1 }} of {{ questions.length }}</p>
        <h3>{{ questions[i].q }}</h3>
        <div style="display: flex; flex-direction: column; gap: 8px;">
          <button
            *ngFor="let opt of questions[i].options; let idx = index"
            (click)="pick(idx)"
            [style.background]="bgFor(idx)"
            [style.cursor]="answered ? 'default' : 'pointer'"
            style="text-align: left; padding: 10px 14px; border-radius: 8px; border: 1px solid #d1d5db;"
          >{{ opt }}</button>
        </div>
        <button (click)="i = i + 1" [disabled]="!answered" style="margin-top: 16px; padding: 8px 16px; cursor: pointer;" [style.opacity]="answered ? 1 : 0.5">
          {{ i === questions.length - 1 ? 'Finish' : 'Next' }}
        </button>
      </ng-container>

      <ng-template #result>
        <h2>Score: {{ score }} / {{ questions.length }}</h2>
        <ul style="padding-left: 18px;">
          <li *ngFor="let q of questions; let idx = index" [style.color]="answers[idx] === q.correct ? '#16a34a' : '#dc2626'" style="margin-bottom: 6px;">
            {{ q.q }} — {{ q.options[q.correct] }}
          </li>
        </ul>
        <button (click)="restart()" style="padding: 8px 16px; cursor: pointer;">Restart</button>
      </ng-template>
    </div>
  `,
})
export class QuizComponent {
  @Input() questions: Question[] = [];
  i = 0;
  answers: Record<number, number> = {};

  get done(): boolean {
    return this.i >= this.questions.length;
  }

  get answered(): boolean {
    return this.answers[this.i] != null;
  }

  get score(): number {
    return this.questions.reduce((s, q, idx) => s + (this.answers[idx] === q.correct ? 1 : 0), 0);
  }

  pick(choice: number): void {
    if (this.answers[this.i] != null) {
      return;
    }
    this.answers = { ...this.answers, [this.i]: choice };
  }

  bgFor(idx: number): string {
    if (!this.answered) {
      return '#fff';
    }
    if (idx === this.questions[this.i].correct) {
      return '#dcfce7';
    }
    if (idx === this.answers[this.i]) {
      return '#fee2e2';
    }
    return '#fff';
  }

  restart(): void {
    this.i = 0;
    this.answers = {};
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Quiz Demo</h1>
      <app-quiz [questions]="questions"></app-quiz>
    </div>
  `,
})
export class AppComponent {
  questions: Question[] = [
    { q: 'Which decorator marks an Angular component?', options: ['@Injectable', '@Component', '@NgModule', '@Directive'], correct: 1 },
    { q: 'What does CSS stand for?', options: ['Cascading Style Sheets', 'Computer Style System', 'Creative Style Sheets', 'Colorful Style Sheets'], correct: 0 },
    { q: 'Which array method returns a new filtered array?', options: ['forEach', 'map', 'filter', 'reduce'], correct: 2 },
  ];
}

@NgModule({
  declarations: [AppComponent, QuizComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
